package org.apache.commons.csv;
import org.apache.commons.csv.CSVParser;
import org.apache.commons.csv.CSVRecord;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.io.Reader;
import java.io.StringReader;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

public class CSVParserTest {

    private CSVParser parser;

    @BeforeEach
    void setUp() {
        // We will create a spy of CSVParser to mock nextRecord() method
        Reader reader = new StringReader("");
        CSVFormat format = CSVFormat.DEFAULT;
        parser = Mockito.spy(new CSVParser(reader, format));
    }

    @AfterEach
    void tearDown() throws IOException {
        if (parser != null && !parser.isClosed()) {
            parser.close();
        }
    }

    @Test
    void testGetRecords_empty() throws IOException {
        // Mock nextRecord() to return null immediately (no records)
        doReturn(null).when(parser).nextRecord();

        List<CSVRecord> records = parser.getRecords();

        assertNotNull(records);
        assertTrue(records.isEmpty());
        verify(parser, times(1)).nextRecord();
    }

    @Test
    void testGetRecords_multipleRecords() throws Exception {
        // Prepare mock CSVRecord instances
        CSVRecord record1 = mock(CSVRecord.class);
        CSVRecord record2 = mock(CSVRecord.class);

        // Mock nextRecord() to return two records then null
        doReturn(record1, record2, null).when(parser).nextRecord();

        List<CSVRecord> records = parser.getRecords();

        assertNotNull(records);
        assertEquals(2, records.size());
        assertSame(record1, records.get(0));
        assertSame(record2, records.get(1));
        verify(parser, times(3)).nextRecord();
    }

    @Test
    void testGetRecords_privateNextRecordViaReflection() throws Exception {
        // Using reflection to invoke private nextRecord() to verify it can be accessed
        Method nextRecordMethod = CSVParser.class.getDeclaredMethod("nextRecord");
        nextRecordMethod.setAccessible(true);

        // Mock nextRecord() to control behavior
        doReturn(null).when(parser).nextRecord();

        Object result = nextRecordMethod.invoke(parser);
        assertNull(result);
    }

    @Test
    void testGetRecords_internalStateAfterCall() throws IOException {
        // Mock nextRecord() to return one record then null
        CSVRecord record = mock(CSVRecord.class);
        doReturn(record, null).when(parser).nextRecord();

        List<CSVRecord> records = parser.getRecords();

        // After getRecords, recordList field should remain accessible and unchanged (empty)
        Field recordListField = CSVParser.class.getDeclaredField("recordList");
        recordListField.setAccessible(true);
        List<?> recordList = (List<?>) recordListField.get(parser);

        // recordList is internal, it may or may not be modified by getRecords, just check not null
        assertNotNull(recordList);

        // Records returned should contain the mocked record
        assertEquals(1, records.size());
        assertSame(record, records.get(0));
    }
}
